const output = $('🤖 AI Video Agent').item.json.output;
const markerMatch = output.match(/VIDEO_READY:\s*(https?:\/\/[^\s)>\]]+)/i);
return [{
  json: {
    video_url: markerMatch ? markerMatch[1] : null,
    has_video: !!markerMatch,
    agent_output: output,
    chat_id: $('📩 Telegram Trigger').item.json.message.chat.id
  }
}];

parameters.message:
={{ "Your video is ready!

" + $json.video_url + "

Would you like to publish it to social media via Blotato?" }}
